import React, { useEffect, useState } from "react";
import JournalCard from "./JournalCard";

const History = ({ onEditEntry }) => {
  const [entries, setEntries] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];
    setEntries(stored.reverse());
  }, []);

  // Delete handler
  const handleDelete = (id) => {
    if (window.confirm("Are you sure you want to delete this entry?")) {
      const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];
      const filtered = stored.filter((e) => e.id !== id);
      localStorage.setItem("journalEntries", JSON.stringify(filtered));
      setEntries(filtered.reverse());
    }
  };

  return (
    <div className="history-page">
      <h1 className="history-heading">Journal History</h1>
      <div className="history-list">
        {entries.length > 0 ? (
          entries.map((entry) => (
            <JournalCard
              key={entry.id}
              id={entry.id}
              title={entry.title}
              date={entry.date}
              entry={entry.entry}
              analyzed={entry.analyzed}
              analysis={entry.analysis}
              onEdit={onEditEntry}
              onDelete={handleDelete}
            />
          ))
        ) : (
          <p>No journal entries found.</p>
        )}
      </div>
      <div className='design-layout'>
        <img className='design' src='/assets/background1.png' alt="Design" />
      </div>

      <style>{`
        .history-page {
          font-family: 'Cedarville Cursive', cursive;
          color: var(--text);
          padding: 1rem;
          display: flex;
          flex-direction: column;
          align-items: center;
        }

        .design-layout {
            display: flex;
            justify-content: center;
            margin: 2rem 0;
            width: 100%;
        }

        .design {
            width: 80%;
            max-width: 700px;
            height: auto;
            opacity: 0.8;
        }

        .history-heading {
          font-size: 2.5rem;
          margin-bottom: 2rem;
        }

        .history-list {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          gap: 1rem;
          width: 100%;
          max-width: 1200px;
        }

        @media (max-width: 600px) {
          .history-heading {
            font-size: 2rem;
          }
        }
      `}</style>
    </div>
  );
};

export default History;
